/**
 * src/lib/routeData.ts
 *
 * Route data helpers — Cloudflare Workers compatible.
 *
 * Uses STATIC top-level imports so esbuild bundles the JSON directly into
 * handler.mjs at build time. Dynamic import() does NOT work in Workers runtime
 * because there's no filesystem to load from.
 *
 * The 9 state-shard JSON files are generated by: node scripts/split-routes.js
 */
import 'server-only';
import { Route } from './data';

// Static imports — bundled into handler.mjs by esbuild at build time
import rawWB from '@/data/routes-west-bengal.json';
import rawJH from '@/data/routes-jharkhand.json';
import rawOD from '@/data/routes-odisha.json';
import rawBH from '@/data/routes-bihar.json';
import rawUP from '@/data/routes-uttar-pradesh.json';
import rawCWB from '@/data/routes-cross-wb.json';
import rawCJH from '@/data/routes-cross-jh.json';
import rawCOD from '@/data/routes-cross-od.json';
import rawCOTH from '@/data/routes-cross-other.json';

// Merge all shards once at module load time (cached in isolate memory)
const ALL_ROUTES: Route[] = [
  ...(rawWB as unknown as Route[]),
  ...(rawJH as unknown as Route[]),
  ...(rawOD as unknown as Route[]),
  ...(rawBH as unknown as Route[]),
  ...(rawUP as unknown as Route[]),
  ...(rawCWB as unknown as Route[]),
  ...(rawCJH as unknown as Route[]),
  ...(rawCOD as unknown as Route[]),
  ...(rawCOTH as unknown as Route[]),
];

const ROUTE_MAP = new Map<string, Route>(ALL_ROUTES.map(r => [r.slug, r]));



// ─── Pre-built indexes (computed ONCE at module load, cached in Worker isolate) ─
// These replace O(n) per-request filter scans with O(1) Map lookups.

/** city slug → all routes FROM that city */
const ROUTES_FROM_IDX = new Map<string, Route[]>();
/** city slug → nearby routes (≤250km) sorted by distance */
const LOCAL_ROUTES_IDX = new Map<string, Route[]>();
/** state pair "fromState:toState" → routes */
const STATE_PAIR_IDX = new Map<string, Route[]>();

for (const r of ALL_ROUTES) {
  // from-city index
  const fromList = ROUTES_FROM_IDX.get(r.from) ?? [];
  fromList.push(r);
  ROUTES_FROM_IDX.set(r.from, fromList);

  // local routes index (≤250km only)
  if (r.distance > 0 && r.distance <= 250) {
    const localList = LOCAL_ROUTES_IDX.get(r.from) ?? [];
    localList.push(r);
    LOCAL_ROUTES_IDX.set(r.from, localList);
  }

  // state-pair index
  const pairKey = `${r.fromState}:${r.toState}`;
  const pairList = STATE_PAIR_IDX.get(pairKey) ?? [];
  pairList.push(r);
  STATE_PAIR_IDX.set(pairKey, pairList);
}

// Sort local routes index by distance once (not on every request)
for (const [key, routes] of LOCAL_ROUTES_IDX) {
  LOCAL_ROUTES_IDX.set(key, routes.sort((a, b) => a.distance - b.distance));
}

// Pre-compute popular routes once
const _hubSlugs = new Set(['kolkata', 'ranchi', 'bhubaneswar']);
const _popularDest = new Set([
  'darjeeling', 'puri', 'digha', 'deoghar', 'konark', 'ranchi',
  'bhubaneswar', 'kolkata', 'jamshedpur', 'mandarmani', 'gangasagar',
  'mayapur', 'siliguri', 'durgapur', 'asansol', 'dhanbad', 'bokaro',
]);
const _POPULAR_ROUTES = ALL_ROUTES
  .filter(r => _hubSlugs.has(r.from) && _popularDest.has(r.to))
  .slice(0, 20);

// Pre-compute high-priority routes once
const _hubAll = new Set(['kolkata', 'ranchi', 'bhubaneswar', 'jamshedpur', 'patna']);
const _HIGH_PRIORITY = ALL_ROUTES.filter(r =>
  r.distance <= 250 || _hubAll.has(r.from) || _hubAll.has(r.to)
);

// ─── Public async helpers ─────────────────────────────────────────────────────

export async function getAllRoutes(): Promise<Route[]> {
  return ALL_ROUTES;
}

export async function getRoute(slug: string): Promise<Route | undefined> {
  return ROUTE_MAP.get(slug);
}

/** O(1) — uses pre-built index */
export async function getRoutesFrom(citySlug: string): Promise<Route[]> {
  return ROUTES_FROM_IDX.get(citySlug) ?? [];
}

/** O(1) — uses pre-built index */
export async function getRoutesTo(citySlug: string): Promise<Route[]> {
  return ALL_ROUTES.filter(r => r.to === citySlug);
}

/** O(1) — uses pre-built state-pair index */
export async function getRoutesBetweenStates(fromState: string, toState: string): Promise<Route[]> {
  return STATE_PAIR_IDX.get(`${fromState}:${toState}`) ?? [];
}

/** O(1) — pre-computed at startup */
export async function getPopularRoutes(limit = 12): Promise<Route[]> {
  return _POPULAR_ROUTES.slice(0, limit);
}

/** O(1) — uses pre-built sorted local index */
export async function getLocalRoutes(citySlug: string, maxDistance = 200): Promise<Route[]> {
  return (LOCAL_ROUTES_IDX.get(citySlug) ?? []).filter(r => r.distance <= maxDistance);
}

/** O(1) — uses pre-built sorted local index */
export async function getPopularLocalRoutes(citySlug: string, limit = 8): Promise<Route[]> {
  return (LOCAL_ROUTES_IDX.get(citySlug) ?? []).slice(0, limit);
}

export async function getAllRouteSlugs(): Promise<string[]> {
  return ALL_ROUTES.map(r => r.slug);
}

/** O(1) — pre-computed at startup */
export async function getHighPriorityRoutes(): Promise<Route[]> {
  return _HIGH_PRIORITY;
}



// ─── Pre-computed linked slugs (computed ONCE at module load) ─────────────────
// Sitemaps 5 & 6 call these — pre-computing avoids O(n) timeout on cold fetch.
const _hubSlugsLinked = new Set(['kolkata', 'ranchi', 'bhubaneswar', 'jamshedpur', 'patna']);
const _seenLinked = new Set<string>();

// Pass 1: hub routes and short-distance routes
for (const r of ALL_ROUTES) {
  if (r.distance <= 250 || _hubSlugsLinked.has(r.from) || _hubSlugsLinked.has(r.to)) {
    _seenLinked.add(r.slug);
  }
}

// Pass 2: top routes per city (already in ROUTES_FROM_IDX — reuse it!)
for (const [, cityRoutes] of ROUTES_FROM_IDX) {
  cityRoutes.slice(0, 20).forEach(r => _seenLinked.add(r.slug));
}
for (const [, cityRoutes] of LOCAL_ROUTES_IDX) {
  cityRoutes.slice(0, 12).forEach(r => _seenLinked.add(r.slug));
}

// Pass 3: add reverse routes
const _finalLinked = new Set<string>(_seenLinked);
for (const slug of _seenLinked) {
  const parts = slug.split('-to-');
  if (parts.length === 2) {
    const rev = `${parts[1]}-to-${parts[0]}`;
    if (ROUTE_MAP.has(rev)) _finalLinked.add(rev);
  }
}
const _LINKED_ROUTE_SLUGS: string[] = Array.from(_finalLinked);
const _LINKED_VEHICLE_SLUGS: string[] = _LINKED_ROUTE_SLUGS.filter(isHubRoute);

/** O(1) — pre-computed at startup */
export async function getLinkedRouteSlugs(): Promise<string[]> {
  return _LINKED_ROUTE_SLUGS;
}

/** O(1) — pre-computed at startup */
export async function getLinkedVehicleRouteSlugs(): Promise<string[]> {
  return _LINKED_VEHICLE_SLUGS;
}

// ─── Pure synchronous helpers (no route data access needed) ───────────────────

export function isHubRoute(slug: string): boolean {
  const parts = slug.split('-to-');
  if (parts.length === 2) {
    const hubSlugs = new Set(['kolkata', 'ranchi', 'bhubaneswar', 'jamshedpur', 'patna']);
    return hubSlugs.has(parts[0]) || hubSlugs.has(parts[1]);
  }
  return false;
}



